            value="+14.2%" 
            icon={<TrendingUp className="w-5 h-5" />}
            color="bg-amber-500 shadow-amber-500/20"
         />
      </div>

      {/* ================= COURSE PERFORMANCE BREAKDOWN ================= */}
      <div className="space-y-8 bg-card border border-border rounded-[3.5rem] p-12 relative overflow-hidden">

