                    })()}

                    {module.assignment && (() => {
                      const navIdx = navItems.findIndex(n => n.id === module.assignment.id);
                      const isActive = activeIndex === navIdx;
                      return (
                        <button key={`asgn-${module.assignment.id}`} onClick={() => goToItem(navIdx)}
