             <p className="text-muted-foreground max-w-md font-medium">
               {t("student.player.completion_desc")}
             </p>
           </div>
        ) : activeItem ? (
          <>
            <div className="flex-1 overflow-y-auto">

              {/* ===== LESSON VIEW ===== */}
              {activeItem.type === 'lesson' && (
                <div className="w-full flex flex-col">
