                            className={`absolute top-0 bottom-0 left-0 ${isCompleted ? 'bg-emerald-400' : 'bg-primary'} transition-all duration-700 rounded-full shadow-[0_0_10px_rgba(255,255,255,0.5)]`}
                            style={{ width: `${course.progressPercentage || 0}%` }}
