"use client";

import React, { useState } from "react";
import { useForm } from "react-hook-form";

import { useCreateCourseMutation, useUpdateCourseMutation } from "@/redux/features/course/courseAPi";
import { useGetCategoriesQuery } from "@/redux/features/category/categoriesApi";
import { ICourse } from "@/interfaces/course.interface";
import toast from "react-hot-toast";
import { useEffect } from "react";

type FormValues = {
  title: string;
  description: string;
  thumbnailFile?: File;
  previewVideo: string;
  price: number;
  categoryId: string;
};

// Convert YouTube URL → embed URL
const convertToEmbedUrl = (url: string) => {
  if (!url) return "";
  if (url.includes("youtu.be/"))
    return url.replace("https://youtu.be/", "https://www.youtube.com/embed/");
  if (url.includes("youtube.com/watch?v=")) {
    const videoId = url.split("v=")[1]?.split("&")[0];
    return `https://www.youtube.com/embed/${videoId}`;
  }
  return url;
};

export default function CourseCreateForm({
  onCreated,
  initialData,
}: {
  onCreated?: (courseId: string) => void;
  initialData?: any;
}) {
  const isEditMode = !!initialData;
  const { register, handleSubmit, reset, setValue, watch } =
    useForm<FormValues>({
      defaultValues: {
        title: initialData?.title || "",
        description: initialData?.description || "",
        previewVideo: initialData?.previewVideo || "",
        price: initialData?.price || 0,
        categoryId: initialData?.categoryId || "",
      },
    });

  const [createCourse] = useCreateCourseMutation();
  const [updateCourse] = useUpdateCourseMutation();
  const { data: categories, isLoading: catLoading, isError } =
    useGetCategoriesQuery();

  const [thumbPreview, setThumbPreview] = useState<string | null>(initialData?.thumbnail || null);
  const [loading, setLoading] = useState(false);

  // Pre-fill form if initialData changes
  useEffect(() => {
    if (initialData) {
      reset({
        title: initialData.title,
        description: initialData.description,
        previewVideo: initialData.previewVideo,
        price: initialData.price,
        categoryId: initialData.categoryId,
      });
      setThumbPreview(initialData.thumbnail);
    }
  }, [initialData, reset]);

  // Thumbnail handler
  const handleThumbChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setValue("thumbnailFile" as any, file);

    const reader = new FileReader();
    reader.onload = () => setThumbPreview(reader.result as string);
    reader.readAsDataURL(file);
  };

  const onSubmit = async (data: FormValues) => {
    if (!isEditMode && !data.thumbnailFile) {
      toast.error("Thumbnail is required for new courses!");
      return;
    }

    if (!data.categoryId) {
      toast.error("Category is required!");
      return;
    }

    try {
      setLoading(true);

      let thumbnailUrl = initialData?.thumbnail || "";

      // Upload to Cloudinary only if a new file is selected
      if (data.thumbnailFile) {
        const fd = new FormData();
        fd.append("file", data.thumbnailFile);
        fd.append("upload_preset", "course_thumbnails");

        const res = await fetch(
          "https://api.cloudinary.com/v1_1/dyfamn6rm/image/upload",
          {
            method: "POST",
            body: fd,
          }
        );

        const json = await res.json();
        thumbnailUrl = json.secure_url;

        if (!thumbnailUrl) {
          toast.error("Thumbnail upload failed!");
          return;
        }
      }

      // Convert video URL
      const embedVideoUrl = convertToEmbedUrl(data.previewVideo);

      // ✅ Correct payload
      const payload: any = {
        title: data.title,
        description: data.description,
        thumbnail: thumbnailUrl,
        previewVideo: embedVideoUrl,
        price: Number(data.price),
        categoryId: data.categoryId,
      };

      if (isEditMode) {
        await updateCourse({ id: initialData.id, data: payload }).unwrap();
        toast.success("✅ Course updated successfully!");
      } else {
        const created = await createCourse(payload).unwrap();
        toast.success("✅ Course created successfully!");

        const createdCourseId =
          (created as any)?.id ??
          (created as any)?._id ??
          (created as any)?.data?.id ??
          (created as any)?.data?._id;

        if (onCreated && createdCourseId) {
          onCreated(createdCourseId);
        }
      }

      if (!isEditMode) {
        reset();
        setThumbPreview(null);
      } else if (onCreated) {
        onCreated(initialData.id);
      }

    } catch (err) {
      console.error("❌ Form submission error:", err);
      toast.error(isEditMode ? "Failed to update course." : "Failed to create course.");
    } finally {
      setLoading(false);
    }
  };

  const previewVideoUrl = watch("previewVideo");

  return (
    <div className="space-y-8">
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">

        <div className="space-y-6">
            <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Course Title</label>
                <input
                {...register("title", { required: true })}
                placeholder="Ex. Advanced Next.js Patterns"
                className="w-full h-14 px-6 bg-secondary/30 border border-transparent rounded-2xl focus:ring-2 focus:ring-primary/20 outline-none transition-all font-bold placeholder:opacity-50"
                />
            </div>

            <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Description</label>
                <textarea
                {...register("description", { required: true })}
                placeholder="Describe what students will learn..."
                rows={4}
                className="w-full px-6 py-4 bg-secondary/30 border border-transparent rounded-2xl focus:ring-2 focus:ring-primary/20 outline-none transition-all font-bold placeholder:opacity-50 resize-none"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Price (USD)</label>
                <input
                    type="number"
                    {...register("price", { required: true, valueAsNumber: true })}
                    placeholder="299"
                    className="w-full h-14 px-6 bg-secondary/30 border border-transparent rounded-2xl focus:ring-2 focus:ring-primary/20 outline-none transition-all font-bold placeholder:opacity-50"
                />
                </div>

                <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Category</label>
                <select
                    {...register("categoryId", { required: true })}
                    className="w-full h-14 px-6 bg-secondary/30 border border-transparent rounded-2xl focus:ring-2 focus:ring-primary/20 outline-none transition-all font-bold text-sm cursor-pointer"
                >
                    <option value="">Select a category</option>
                    {catLoading && <option>Loading...</option>}
                    {isError && <option>Error loading</option>}
                    {categories?.data?.map((cat: any) => (
                    <option key={cat.id} value={cat.id}>
                        {cat.name}
                    </option>
                    ))}
                </select>
                </div>
            </div>

            <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Preview Video URL</label>
                <input
                {...register("previewVideo", { required: true })}
                placeholder="YouTube URL"
                className="w-full h-14 px-6 bg-secondary/30 border border-transparent rounded-2xl focus:ring-2 focus:ring-primary/20 outline-none transition-all font-bold placeholder:opacity-50"
                />
            </div>

            {/* Video Preview */}
            {previewVideoUrl && (
            <div className="rounded-2xl overflow-hidden border border-border/50 relative pt-[56.25%]">
                <iframe
                className="absolute inset-0 w-full h-full"
                src={convertToEmbedUrl(previewVideoUrl)}
                ></iframe>
            </div>
            )}

            {/* Thumbnail */}
            <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-muted-foreground ml-1">Course Thumbnail</label>
                <div className="flex items-center gap-6">
                    <div className="flex-1">
                        <input 
                            type="file" 
                            accept="image/*" 
                            onChange={handleThumbChange} 
                            className="w-full text-sm text-muted-foreground file:mr-4 file:py-3 file:px-6 file:rounded-xl file:border-0 file:text-xs file:font-black file:uppercase file:tracking-widest file:bg-primary/10 file:text-primary hover:file:bg-primary/20 transition-all cursor-pointer bg-secondary/30 rounded-2xl h-14 flex items-center pr-2"
                        />
                    </div>
                    {thumbPreview && (
                        <div className="w-32 h-20 rounded-xl overflow-hidden border border-border/50 flex-shrink-0">
                            <img
                                src={thumbPreview}
                                className="w-full h-full object-cover"
                            />
                        </div>
                    )}
                </div>
            </div>

        </div>

        <button
          type="submit"
          disabled={loading}
          className="w-full h-16 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-sm flex items-center justify-center gap-3 shadow-xl shadow-primary/20 hover:scale-[1.01] active:scale-95 disabled:opacity-50 transition-all mt-8"
        >
          {loading ? (isEditMode ? "Updating..." : "Creating...") : (isEditMode ? "Update Course" : "Create Course")}
        </button>
      </form>
    </div>
  );
}

"use client"

import React, { useMemo } from 'react'
import { useTranslation, Trans } from 'react-i18next'
import { 
  TrendingUp, 
  DollarSign, 
  Users, 
  PieChart as PieChartIcon,
  ArrowUpRight,
  ArrowDownRight,
  Activity,
  Zap,
  ShieldCheck,
  Inbox
} from 'lucide-react'

interface ChartData {
  label: string
  value: number
}

export function PlatformAnalytics({ 
  courses = [], 
  users = [], 
  statistics = {} 
}: { 
  courses?: any[], 
  users?: any[], 
  statistics?: any 
}) {
  const { t } = useTranslation()

  // 📈 Calculate Real Revenue Data from Courses
  const revenueData = useMemo(() => {
    // Grouping revenue by month based on course creation (as a fallback if real sales history is missing)
    // Or just showing the distribution of revenue across top courses
    const sortedCourses = [...courses].sort((a, b) => 
        (b.price * (b._count?.enrolledUsers || 0)) - (a.price * (a._count?.enrolledUsers || 0))
    ).slice(0, 12);

    return sortedCourses.map(c => (c.price * (c._count?.enrolledUsers || 0)));
  }, [courses]);

  // 📂 Calculate Real Course Distribution
  const courseDistribution = useMemo(() => {
    const categories: Record<string, { count: number, color: string }> = {};
    const colors = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ec4899', '#6366f1'];

    courses.forEach((c, i) => {
        const catName = c.category?.name || 'Uncategorized';
        if (!categories[catName]) {
            categories[catName] = { count: 0, color: colors[Object.keys(categories).length % colors.length] };
        }
        categories[catName].count++;
    });

    const total = courses.length || 1;
    return Object.entries(categories).map(([label, data]) => ({
        label,
        value: Math.round((data.count / total) * 100),
        color: data.color
    })).sort((a, b) => b.value - a.value).slice(0, 4);
  }, [courses]);

  // 👥 Sanitize and shared user list
  const userList = useMemo(() => Array.isArray(users) ? users : [], [users]);

  // 👥 Calculate User Registration Trends (Last 7 Days)
  const userTrends = useMemo(() => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    // Helper to get YYYY-MM-DD in local time
    const formatDate = (date: Date) => {
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    };

    const last7Days = Array.from({ length: 7 }, (_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - i);
        return {
            full: formatDate(d),
            label: days[d.getDay()]
        };
    }).reverse();

    const activityMap: Record<string, number> = {};
    last7Days.forEach(day => activityMap[day.full] = 0);

    userList.forEach(u => {
        const dateStr = u.createdAt || u.joinDate;
        if (!dateStr) return;

        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return;

        const date = formatDate(d);
        if (activityMap[date] !== undefined) {
            activityMap[date]++;
        }
    });

    return last7Days.map(day => ({
        label: day.label,
        value: activityMap[day.full]
    }));
  }, [userList]);

  const userActivity = useMemo(() => userTrends.map(t => t.value), [userTrends]);

  // 🕒 User Activity Stats
  const activityStats = useMemo(() => {
    const now = new Date();
    const lastWeek = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const lastMonth = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    return {
        newThisWeek: userList.filter(u => {
            const dateStr = u.createdAt || u.joinDate;
            if (!dateStr) return false;
            const d = new Date(dateStr);
            return !isNaN(d.getTime()) && d > lastWeek;
        }).length,
        newThisMonth: userList.filter(u => {
            const dateStr = u.createdAt || u.joinDate;
            if (!dateStr) return false;
            const d = new Date(dateStr);
            return !isNaN(d.getTime()) && d > lastMonth;
        }).length,
    }
  }, [userList]);

  // 📂 Export to CSV Logic
  const handleExportCSV = () => {
    const headers = ["ID", "Title", "Price", "Enrollments", "Revenue"];
    const rows = courses.map(c => [
        c.id,
        `"${c.title}"`,
        c.price,
        c._count?.enrolledUsers || 0,
        c.price * (c._count?.enrolledUsers || 0)
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
        + headers.join(",") + "\n" 
        + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `platform_analytics_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleExportPDF = () => {
    window.print();
  };

  return (
    <div className="space-y-10 print:p-0">
      {/* Analytics Action Bar */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-6 bg-secondary/30 border border-border/40 p-6 rounded-[2rem] no-print">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-primary/10 rounded-2xl flex items-center justify-center border border-primary/20">
                  <ShieldCheck className="w-6 h-6 text-primary" />
              </div>
              <div>
                  <h4 className="text-sm font-black italic">{t("admin.analytics.export_center")}</h4>
                  <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold">{t("admin.analytics.data_aggregation")}</p>
              </div>
          </div>
          <div className="flex items-center gap-3 w-full md:w-auto">
              <button 
                onClick={handleExportCSV}
                className="flex-1 md:flex-none px-6 py-3 bg-card border border-border/60 hover:border-primary/50 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2"
              >
                  <Inbox className="w-3.5 h-3.5" /> {t("admin.analytics.csv_export")}
              </button>
              <button 
                onClick={handleExportPDF}
                className="flex-1 md:flex-none px-6 py-3 bg-primary text-primary-foreground rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2 hover:scale-105 active:scale-95"
              >
                  <TrendingUp className="w-3.5 h-3.5" /> {t("admin.analytics.pdf_report")}
              </button>
          </div>
      </div>
      {/* Analytics Grid */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">

        {/* Revenue Stream Analysis */}
        <div className="bg-card border border-border/60 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden group">
          <div className="flex items-center justify-between mb-10">
            <div className="space-y-1">
              <h3 className="text-xl font-black italic flex items-center gap-2">
                <DollarSign className="w-5 h-5 text-emerald-500" />
                ${statistics.totalRevenue?.toLocaleString() || 0}
              </h3>
              <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground opacity-60">
                {t('admin.analytics.revenue_stream')}
              </p>
            </div>
            <div className="flex items-center gap-2 px-3 py-1 bg-emerald-500/10 text-emerald-500 rounded-full text-[10px] font-black uppercase tracking-widest border border-emerald-500/20">
              <ArrowUpRight className="w-3 h-3" /> +{statistics.engagementRate || 0}%
            </div>
          </div>

          <div className="h-64 w-full relative">
            <AreaChart data={revenueData} color="#10b981" />
          </div>

          <div className="grid grid-cols-4 gap-4 mt-8 pt-8 border-t border-border/40">
             <div className="space-y-1">
                <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">{t("admin.analytics.growth")}</p>
                <p className="text-sm font-black italic">+{statistics.engagementRate || 0}%</p>
