'use client';

import { useEffect } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { useDispatch } from 'react-redux';
import { auth } from '@/lib/firebase';
import { setUser, logout, authStart, setLoading } from '@/redux/features/auth/authSlice';
import { useSyncFirebaseMutation } from '@/redux/features/auth/authApi';

export default function FirebaseAuthProvider({ children }: { children: React.ReactNode }) {
  const dispatch = useDispatch();
  const [syncFirebase] = useSyncFirebaseMutation();

  useEffect(() => {
    // We don't need authStart() here if initialState loading is true, 
    // but it doesn't hurt. However, let's keep it simple.
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const payload = {
          email: firebaseUser.email,
          name: firebaseUser.displayName || firebaseUser.email?.split('@')[0] || 'User',
          avatar: firebaseUser.photoURL,
        };

        try {
          const response = await syncFirebase(payload).unwrap();
          const { user, accessToken } = response.data;
          dispatch(setUser({ user, token: accessToken }));
        } catch (error) {
          console.error("❌ Firebase sync error:", error);
          const fallbackUser = {
            id: firebaseUser.uid,
            name: payload.name,
            email: firebaseUser.email || '',
            password: '',
            role: 'student' as any,
            status: 'active' as any,
            avatar: firebaseUser.photoURL,
            joinDate: new Date().toISOString(),
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          };
          dispatch(setUser({ user: fallbackUser, token: '' }));
        }
      } else {
        // If no firebase user, we just stop the loading state.
        // We don't call logout() because the user might be logged in via email/password (non-firebase).
        dispatch(setLoading(false));
      }
    });

    return () => unsubscribe();
  }, [dispatch, syncFirebase]);

  return <>{children}</>;
}

"use client";

import React, { createContext, useContext, useEffect, useState, ReactNode } from "react";
import { io, Socket } from "socket.io-client";
import { useAppSelector } from "@/redux/hooks"; // Assumes you have Redux for Auth Token if needed

// Define the shape of our context
interface SocketContextType {
  socket: Socket | null;
  isConnected: boolean;
}

// Create the context with default values
const SocketContext = createContext<SocketContextType>({
  socket: null,
  isConnected: false,
});

// Custom hook to easily access the socket instance from any component
export const useSocket = () => useContext(SocketContext);

interface SocketProviderProps {
  children: ReactNode;
}

export const SocketProvider = ({ children }: SocketProviderProps) => {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);

  // Example: Grab token from Redux if you need authenticated sockets
  // const { token } = useAppSelector((state) => state.cmAuth);

  useEffect(() => {
    // ---------------------------------------------------------
    // DEVELOPER NOTE:
    // Initialize the socket connection. 
    // Ensure the backend URL is correctly set in your .env file
    // as NEXT_PUBLIC_API_URL (e.g., http://localhost:5000)
    // ---------------------------------------------------------
    const socketUrl = process.env.NEXT_PUBLIC_API_URL?.replace('/api/v1', '') || "http://localhost:5000";

    const socketInstance = io(socketUrl, {
      // Optional: Add authentication headers if your backend requires them
      // auth: {
      //   token: token, 
      // },
      transports: ["websocket", "polling"], // prioritize websocket for speed
      autoConnect: true,
    });

    socketInstance.on("connect", () => {
      console.log("🟢 [Socket.IO] Connected to server:", socketInstance.id);
      setIsConnected(true);
    });

    socketInstance.on("disconnect", () => {
      console.log("🔴 [Socket.IO] Disconnected from server");
      setIsConnected(false);
    });

    // Save instance to state so we can provide it down the tree
    setSocket(socketInstance);

    // Cleanup function: disconnect when the provider unmounts
    return () => {
      socketInstance.disconnect();
    };
  }, []); // Re-run if `token` changes (if you uncomment token logic)

  return (
    <SocketContext.Provider value={{ socket, isConnected }}>
      {children}
    </SocketContext.Provider>
  );
};

import { IUser } from "@/interfaces/user.interface";
import { createApi, fetchBaseQuery } from "@reduxjs/toolkit/query/react";
import { Mutex } from "async-mutex";
import { logout, setUser } from "../features/auth/authSlice";

interface ITokenAndRefresh {
  accessToken: string;
  user: IUser;
}

interface IRefreshResponse {
  data: ITokenAndRefresh;
}

// Mutex to prevent multiple token refresh at once
const mutex = new Mutex();

const baseQuery = fetchBaseQuery({
  baseUrl:`${process.env.NEXT_PUBLIC_API_URL}/api`,
  credentials: "include",
  prepareHeaders: (headers, { getState }) => {
    const token = (getState() as any).cmAuth.token;
    if (token) {
      headers.set("authorization", `Bearer ${token}`);
    }
    return headers;
  },
});

const baseQueryWithReauth: typeof baseQuery = async (
  args,
  api,
  extraOptions
) => {
  await mutex.waitForUnlock();

  // console.log('🔵 API Request Initiated:', args);

  let result = await baseQuery(args, api, extraOptions);

  if (result?.error?.status === 401) {
    // console.warn('⚠️ 401 Unauthorizationd — trying to refresh token');

    if (!mutex.isLocked()) {
      const release = await mutex.acquire();
      try {
        // console.log('🔁 Attempting token refresh...');

        const refreshResult = await baseQuery(
          { url: "/auth/refresh-token", method: "GET" },
          api,
          extraOptions
        );

        const resultData = refreshResult.data as any;

        if (resultData?.success) {
          const newToken = resultData.data.accessToken;

          // Get the current user from state instead of relying on refresh response
          const currentUser = (api.getState() as any).cmAuth.user;

          api.dispatch(setUser({ user: currentUser, token: newToken }));
          result = await baseQuery(args, api, extraOptions);
        } else {
          api.dispatch(logout());
        }
      } finally {
        release();
      }
    } else {
      // console.log('⏳ Waiting for mutex unlock...');
      await mutex.waitForUnlock();
      result = await baseQuery(args, api, extraOptions);
    }
  }

  // console.log('🟢 Final API Response:', result);
  return result;
};

const baseApi = createApi({
  reducerPath: "baseApi",
  baseQuery: baseQueryWithReauth,
  tagTypes: [
    "Auth",
    "User",
    "Course",
    "Dashboard",
    "Payment",
    "Category",
    "Assignment",
    "Quiz",
    "Enroll",
    "Lesson",
    "Reviews",
    "LiveSession",
    "Job",
    "Newsletter"
  ],
  endpoints: () => ({}),
});


export default baseApi;

